import { useEffect, useState } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

function NavBar() {
  const { isAuthenticated, role, logout } = useAuth();
  const navigate = useNavigate();
  const [darkMode, setDarkMode] = useState(() => localStorage.getItem('theme') === 'dark');

  useEffect(() => {
    document.body.classList.toggle('dark-mode', darkMode);
    localStorage.setItem('theme', darkMode ? 'dark' : 'light');
  }, [darkMode]);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav className='navbar navbar-expand-lg sticky-top bg-white border-bottom shadow-sm'>
      <div className='container'>
        <Link className='navbar-brand fw-bold text-danger' to='/'>
          RescueLink
        </Link>

        <button
          className='navbar-toggler'
          type='button'
          data-bs-toggle='collapse'
          data-bs-target='#mainNav'
          aria-controls='mainNav'
          aria-expanded='false'
          aria-label='Toggle navigation'
        >
          <span className='navbar-toggler-icon' />
        </button>

        <div className='collapse navbar-collapse' id='mainNav'>
          <div className='navbar-nav ms-auto align-items-lg-center gap-lg-2'>
            <NavLink className='nav-link' to='/'>Home</NavLink>
            <NavLink className='nav-link' to='/hospitals'>Hospitals</NavLink>
            <NavLink className='nav-link' to='/donors'>Donors</NavLink>
            <button
              type='button'
              className='btn btn-sm btn-outline-secondary'
              onClick={() => setDarkMode((prev) => !prev)}
              aria-label='Toggle dark mode'
            >
              {darkMode ? 'Light' : 'Dark'}
            </button>

            {isAuthenticated ? (
              <>
                <NavLink className='nav-link' to={role === 'ADMIN' ? '/admin' : '/dashboard'}>
                  Dashboard
                </NavLink>
                <NavLink className='nav-link' to='/profile'>Profile</NavLink>
                <button className='btn btn-outline-danger btn-sm' onClick={handleLogout}>Logout</button>
              </>
            ) : (
              <>
                <NavLink className='btn btn-outline-danger btn-sm' to='/login'>Login</NavLink>
                <NavLink className='btn btn-danger btn-sm' to='/register'>Register</NavLink>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}

export default NavBar;
